app.config["MAX_CONTENT_LENGTH"] = 16 * 1024 * 1024  # 16MB max


class FaceRecognitionSystem:
    def __init__(self):
        self.model: Optional[CalibratedClassifierCV] = None
        self.label_encoder: Optional[LabelEncoder] = None
        self.known_encodings = []
        self.known_labels = []
        self._load_model()

    def _load_model(self):
        """Load the trained model and label encoder from disk if they exist."""
        if os.path.exists(MODEL_PATH) and os.path.exists(ENCODER_PATH):
            try:
                with open(MODEL_PATH, "rb") as f:
                    self.model = pickle.load(f)
                with open(ENCODER_PATH, "rb") as f:
                    self.label_encoder = pickle.load(f)
                logger.info("Model and label encoder loaded successfully.")
            except Exception as e:
                logger.error(f"Error loading model: {e}")
                self.model = None
                self.label_encoder = None

    def _save_model(self):
        """Save the trained model and label encoder to disk."""
        with open(MODEL_PATH, "wb") as f:
            pickle.dump(self.model, f)
        with open(ENCODER_PATH, "wb") as f:
            pickle.dump(self.label_encoder, f)
        logger.info("Model and label encoder saved successfully.")

    def add_employee_photos(self, employee_id: str, employee_name: str, photo_paths: list) -> dict:
        """
        Add employee photos to the training data directory.
        Returns a summary of processed photos.
        """
        employee_dir = os.path.join(TRAINING_DATA_FOLDER, f"{employee_id}_{employee_name}")
        os.makedirs(employee_dir, exist_ok=True)

        results = {"employee_id": employee_id, "employee_name": employee_name, "photos_processed": 0, "photos_failed": 0, "errors": []}

        for photo_path in photo_paths:
            try:
                image = face_recognition.load_image_file(photo_path)
                encodings = face_recognition.face_encodings(image)

                if len(encodings) == 0:
                    results["photos_failed"] += 1
                    results["errors"].append(f"No face detected in {os.path.basename(photo_path)}")
                    continue

                if len(encodings) > 1:
                    results["errors"].append(
                        f"Multiple faces detected in {os.path.basename(photo_path)}, using the first one."
                    )

                # Copy photo to training directory
                import shutil
                dest = os.path.join(employee_dir, os.path.basename(photo_path))
                if os.path.abspath(photo_path) != os.path.abspath(dest):
                    shutil.copy2(photo_path, dest)

                results["photos_processed"] += 1

            except Exception as e:
                results["photos_failed"] += 1
                results["errors"].append(f"Error processing {os.path.basename(photo_path)}: {str(e)}")

        return results

    def train(self) -> dict:
        """
        Train the facial recognition model on all employee photos in the training data directory.
        Uses a calibrated SVM for probability estimation.
        """
        encodings = []
        labels = []
        employee_info = {}

        training_path = Path(TRAINING_DATA_FOLDER)

        if not training_path.exists() or not any(training_path.iterdir()):
            return {"success": False, "error": "No training data found. Please add employee photos first."}

        for employee_dir in training_path.iterdir():
            if not employee_dir.is_dir():
                continue

            dir_name = employee_dir.name
            parts = dir_name.split("_", 1)
            if len(parts) == 2:
                emp_id, emp_name = parts
            else:
                emp_id = dir_name
                emp_name = dir_name

            employee_info[dir_name] = {"employee_id": emp_id, "employee_name": emp_name}

            photo_count = 0
            for photo_file in employee_dir.iterdir():
                if photo_file.suffix.lower().lstrip(".") not in ALLOWED_EXTENSIONS:
                    continue

                try:
                    image = face_recognition.load_image_file(str(photo_file))
                    face_encodings = face_recognition.face_encodings(image)

                    if len(face_encodings) > 0:
                        encodings.append(face_encodings[0])
                        labels.append(dir_name)
                        photo_count += 1

                except Exception as e:
                    logger.warning(f"Error processing {photo_file}: {e}")

            employee_info[dir_name]["photos_used"] = photo_count

        if len(encodings) < 2:
            return {"success": False, "error": "Not enough training data. Need at least 2 face images."}

        unique_labels = set(labels)
        if len(unique_labels) < 2:
            return {"success": False, "error": "Need at least 2 different employees for training."}

        # Check each class has enough samples
        from collections import Counter
        label_counts = Counter(labels)
        min_samples_per_class = 1

        for label, count in label_counts.items():
            if count < min_samples_per_class:
                return {
                    "success": False,
                    "error": f"Employee '{label}' has only {count} photo(s). Need at least {min_samples_per_class}.",
                }

        # Encode labels
        self.label_encoder = LabelEncoder()
        encoded_labels = self.label_encoder.fit_transform(labels)

        # Train SVM with probability calibration
        X = np.array(encodings)
        y = encoded_labels

        # Use SVC with calibration for better probability estimates
        base_svm = SVC(kernel="rbf", gamma="scale", C=10.0, probability=False)
        
        # Determine cv folds based on minimum class count
        min_class_count = min(label_counts.values())
        cv_folds = min(5, min_class_count) if min_class_count >= 2 else 2
        
        if min_class_count >= 2:
            self.model = CalibratedClassifierCV(base_svm, cv=cv_folds, method="sigmoid")
        else:
            # Fallback: use prefit calibration or direct SVC with probability=True
            base_svm_prob = SVC(kernel="rbf", gamma="scale", C=10.0, probability=True)
            base_svm_prob.fit(X, y)
            self.model = base_svm_prob

        if isinstance(self.model, CalibratedClassifierCV):
            self.model.fit(X, y)

        self._save_model()

        # Store encodings for distance-based fallback
        self.known_encodings = encodings
        self.known_labels = labels

        training_summary = {
            "success": True,
            "total_photos_used": len(encodings),
            "total_employees": len(unique_labels),
            "employees": {},
            "trained_at": datetime.now().isoformat(),
        }

        for label in unique_labels:
            info = employee_info.get(label, {})
            training_summary["employees"][label] = {
                "employee_id": info.get("employee_id", label),
                "employee_name": info.get("employee_name", label),
                "photos_used": info.get("photos_used", 0),
            }

        return training_summary

    def recognize(self, image_path: str, distance_threshold: float = 0.6) -> dict:
        """
        Recognize a face in the given image. Returns confidence scores for all known employees.
        Also computes face distance-based scores as supplementary information.
        """
        if self.model is None or self.label_encoder is None:
            return {"success": False, "error": "Model not trained. Please train the model first."}

        try:
            image = face_recognition.load_image_file(image_path)
        except Exception as e:
            return {"success": False, "error": f"Could not load image: {str(e)}"}

        face_locations = face_recognition.face_locations(image, model="hog")

        if len(face_locations) == 0:
            return {"success": False, "error": "No face detected in the image."}

        face_encodings = face_recognition.face_encodings(image, face_locations)

        results = {
            "success": True,
            "faces_detected": len(face_locations),
            "results": [],
            "timestamp": datetime.now().isoformat(),
        }

        for idx, (face_encoding, face_location) in enumerate(zip(face_encodings, face_locations)):
            face_result = self._analyze_face(face_encoding, face_location, idx, distance_threshold)
            results["results"].append(face_result)

        return results

    def _analyze_face(
        self, face_encoding: np.ndarray, face_location: tuple, face_index: int, distance_threshold: float
    ) -> dict:
        """Analyze a single face encoding and return detailed probability distribution."""
        top, right, bottom, left = face_location

        # Get SVM probability distribution
        encoding_array = face_encoding.reshape(1, -1)
        probabilities = self.model.predict_proba(encoding_array)[0]
        classes = self.label_encoder.classes_

        # Build probability distribution
        probability_distribution = {}
        for cls, prob in zip(classes, probabilities):
            parts = cls.split("_", 1)
            emp_id = parts[0] if len(parts) == 2 else cls
            emp_name = parts[1] if len(parts) == 2 else cls

            probability_distribution[cls] = {
                "employee_id": emp_id,
                "employee_name": emp_name,
                "svm_confidence": round(float(prob), 6),
            }

        # Compute face distance-based scores for each known employee
        # Group known encodings by label
        from collections import defaultdict
        label_encodings = defaultdict(list)

        # Reload training encodings for distance computation
        training_path = Path(TRAINING_DATA_FOLDER)
        for employee_dir in training_path.iterdir():
            if not employee_dir.is_dir():
                continue
            dir_name = employee_dir.name
            for photo_file in employee_dir.iterdir():
                if photo_file.suffix.lower().lstrip(".") not in ALLOWED_EXTENSIONS:
                    continue
                try:
                    img = face_recognition.load_image_file(str(photo_file))
                    encs = face_recognition.face_encodings(img)
                    if encs:
                        label_encodings[dir_name].append(encs[0])
                except Exception:
                    pass

        for cls in classes:
            if cls in label_encodings and label_encodings[cls]:
                distances = face_recognition.face_distance(label_encodings[cls], face_encoding)
                min_distance = float(np.min(distances))
                avg_distance = float(np.mean(distances))
                # Convert distance to a similarity score (0-1, higher is better)
                distance_score = max(0.0, 1.0 - min_distance)
                avg_distance_score = max(0.0, 1.0 - avg_distance)

                probability_distribution[cls]["min_face_distance"] = round(min_distance, 6)
                probability_distribution[cls]["avg_face_distance"] = round(avg_distance, 6)
                probability_distribution[cls]["distance_similarity_score"] = round(distance_score, 6)
                probability_distribution[cls]["avg_distance_similarity_score"] = round(avg_distance_score, 6)
                probability_distribution[cls]["within_threshold"] = min_distance <= distance_threshold
            else:
                probability_distribution[cls]["min_face_distance"] = None
                probability_distribution[cls]["avg_face_distance"] = None
                probability_distribution[cls]["distance_similarity_score"] = None
                probability_distribution[cls]["avg_distance_similarity_score"] = None
                probability_distribution[cls]["within_threshold"] = False

        # Compute combined score (weighted average of SVM confidence and distance similarity)
        for cls in classes:
            svm_conf = probability_distribution[cls]["svm_confidence"]
            dist_sim = probability_distribution[cls].get("distance_similarity_score")
            if dist_sim is not None:
                combined = 0.5 * svm_conf + 0.5 * dist_sim
                probability_distribution[cls]["combined_confidence"] = round(combined, 6)
            else:
                probability_distribution[cls]["combined_confidence"] = round(svm_conf, 6)

        # Sort by combined confidence
        sorted_classes = sorted(classes, key=lambda c: probability_distribution[c]["combined_confidence"], reverse=True)

        # Determine best match
        best_match_class = sorted_classes[0]
        best_match = probability_distribution[best_match_class]
        is_recognized = (
            best_match["combined_confidence"] > 0.4
            and best_match.get("within_threshold", False)
        )

        # Build sorted ranking
        ranking = []
        for rank, cls in enumerate(sorted_classes, 1):
            entry = {"rank": rank, **probability_distribution[cls]}
            ranking.append(entry)

        face_result = {
            "face_index": face_index,
            "face_location": {"top": top, "right": right, "bottom": bottom, "left": left},
            "is_recognized": is_recognized,
            "best_match": {
                "employee_id": best_match["employee_id"],
                "employee_name": best_match["employee_name"],
                "combined_confidence": best_match["combined_confidence"],
                "svm_confidence": best_match["svm_confidence"],
                "min_face_distance": best_match.get("min_face_distance"),
                "within_distance_threshold": best_match.get("within_threshold", False),
            },
            "confidence_ranking": ranking,
            "probability_distribution": probability_distribution,
            "distance_threshold_used": 0.6,
        }

        return face_result


# Initialize the system
face_system = FaceRecognitionSystem()


def allowed_file(filename: str) -> bool:
    return "." in filename and filename.rsplit(".", 1)[1].lower() in ALLOWED_EXTENSIONS


@app.route("/api/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    model_loaded = face_system.model is not None
    return jsonify(
        {
            "status": "healthy",
            "model_loaded": model_loaded,
            "timestamp": datetime.now().isoformat(),
        }
    )


@app.route("/api/employees/enroll", methods=["POST"])
def enroll_employee():
    """
    Enroll a new employee with their photos.
    Expects multipart form data with:
    - employee_id: string
    - employee_name: string
    - photos: one or more image files
    """
    if "employee_id" not in request.form:
        return jsonify({"success": False, "error": "employee_id is required"}), 400

    if "employee_name" not in request.form:
        return jsonify({"success": False, "error": "employee_name is required"}), 400

    if "photos" not in request.files:
        return jsonify({"success": False, "error": "At least one photo is required"}), 400

    employee_id = request.form["employee_id"]
    employee_name = request.form["employee_name"]
    photos = request.files.getlist("photos")

    if not photos:
        return jsonify({"success": False, "error": "At least one photo is required"}), 400

    saved_paths = []
    for photo in photos:
        if photo and allowed_file(photo.filename):
            filename = secure_filename(photo.filename)
            # Add timestamp to avoid collisions
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")
            filename = f"{timestamp}_{filename}"
            filepath = os.path.join(app.config["UPLOAD_FOLDER"], filename)
            photo.save(filepath)
            saved_paths.append(filepath)

    if not saved_paths:
        return jsonify({"success": False, "error": "No valid photo files provided"}), 400

    result = face_system.add_employee_photos(employee_id, employee_name, saved_paths)

    # Clean up upload folder
    for path in saved_paths:
        # Photos are already copied to training_data, but we keep them for reference
        pass

    return jsonify(result)


@app.route("/api/model/train", methods=["POST"])
def train_model():
    """Train the facial recognition model on all enrolled employee photos."""
    logger.info("Training model...")
    result = face_system.train()

    if result.get("success"):
        return jsonify(result)
    else:
        return jsonify(result), 400


@app.route("/api/recognize", methods=["POST"])
def recognize_face():
    """
    Recognize a face in an uploaded image.
    Returns confidence scores for ALL known employees (probability distribution).
    
    Expects multipart form data with:
    - image: image file
    - threshold (optional): distance threshold (default 0.6)
    """
    if "image" not in request.files:
        return jsonify({"success": False, "error": "Image file is required"}), 400

    image_file = request.files["image"]

    if not image_file or not allowed_file(image_file.filename):
        return jsonify({"success": False, "error": "Invalid image file"}), 400

    threshold = float(request.form.get("threshold", 0.6))

    filename = secure_filename(image_file.filename)
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")
    filename = f"recognize_{timestamp}_{filename}"
    filepath = os.path.join(app.config["UPLOAD_FOLDER"], filename)
    image_file.save(filepath)

    try:
        result = face_system.recognize(filepath, distance_threshold=threshold)

        if result.get("success"):
            return jsonify(result)
        else:
            return jsonify(result), 400
    finally:
        # Clean up
        if os.path.exists(filepath):
            os.remove(filepath)


@app.route("/api/employees", methods=["GET"])
def list_employees():
    """List all enrolled employees."""
    training_path = Path(TRAINING_DATA_FOLDER)
    employees = []

    if training_path.exists():
        for employee_dir in sorted(training_path.iterdir()):
            if not employee_dir.is_dir():
                continue

            dir_name = employee_dir.name
            parts = dir_name.split("_", 1)
            emp_id = parts[0] if len(parts) == 2 else dir_name
            emp_name = parts[1] if len(parts) == 2 else dir_name

            photo_count = sum(
                1
                for f in employee_dir.iterdir()
                if f.suffix.lower().lstrip(".") in ALLOWED_EXTENSIONS
            )

            employees.append(
                {
                    "employee_id": emp_id,
                    "employee_name": emp_name,
                    "directory": dir_name,
                    "photo_count": photo_count,
                }
            )

    return jsonify(
        {
            "success": True,
            "total_employees": len(employees),
            "employees": employees,
        }
    )


@app.route("/api/employees/<employee_id>", methods=["DELETE"])
def delete_employee(employee_id: str):
    """Delete an employee and their training data."""
    training_path = Path(TRAINING_DATA_FOLDER)
    deleted = False

    if training_path.exists():
        for employee_dir in training_path.iterdir():
            if employee_dir.is_dir() and employee_dir.name.startswith(f"{employee_id}_"):
                import shutil
                shutil.rmtree(employee_dir)
                deleted = True
                break

    if deleted:
        return jsonify(
            {
                "success": True,
                "message": f"Employee {employee_id} deleted. Please retrain the model.",
            }
        )
    else:
        return jsonify({"success": False, "error": f"Employee {employee_id} not found"}), 404


@app.route("/api/model/status", methods=["GET"])
def model_status():
    """Get the current model status."""
    model_exists = os.path.exists(MODEL_PATH)
    model_loaded = face_system.model is not None

    classes = []
    if face_system.label_encoder is not None:
        for cls in face_system.label_encoder.classes_:
            parts = cls.split("_", 1)
            classes.append(
                {
                    "employee_id": parts[0] if len(parts) == 2 else cls,
                    "employee_name": parts[1] if len(parts) == 2 else cls,
                    "class_label": cls,
                }
            )

    return jsonify(
        {
            "success": True,
            "model_file_exists": model_exists,
            "model_loaded": model_loaded,
            "number_of_classes": len(classes),
            "classes": classes,
        }
    )


@app.route("/api/recognize/batch", methods=["POST"])
def recognize_batch():
    """
    Recognize faces in multiple images.
    Expects multipart form data with:
    - images: multiple image files
    - threshold (optional): distance threshold (default 0.6)
    """
    if "images" not in request.files:
        return jsonify({"success": False, "error": "Image files are required"}), 400

    images = request.files.getlist("images")
    threshold = float(request.form.get("threshold", 0.6))

    if not images:
        return jsonify({"success": False, "error": "At least one image is required"}), 400

    batch_results = {
        "success": True,
        "total_images": len(images),
        "results": [],
        "timestamp": datetime.now().isoformat(),
    }

    for image_file in images:
        if not image_file or not allowed_file(image_file.filename):
            batch_results["results"].append(
                {
                    "filename": image_file.filename if image_file else "unknown",
                    "success": False,
                    "error": "Invalid image file",
                }
            )
            continue

        filename = secure_filename(image_file.filename)
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")
        temp_filename = f"batch_{timestamp}_{filename}"
        filepath = os.path.join(app.config["UPLOAD_FOLDER"], temp_filename)
        image_file.save(filepath)

        try:
            result = face_system.recognize(filepath, distance_threshold=threshold)
            result["original_filename"] = image_file.filename
            batch_results["results"].append(result)
        finally:
            if os.path.exists(filepath):
                os.remove(filepath)

    return jsonify(batch_results)


@app.errorhandler(413)
def too_large(e):
    return jsonify({"success": False, "error": "File too large. Maximum size is 16MB."}), 413


@app.errorhandler(404)
def not_found(e):
    return jsonify({"success": False, "error": "Endpoint not found."}), 404


@app.errorhandler(500)
def internal_error(e):
    return jsonify({"success": False, "error": "Internal server error."}), 500


